import{_ as a,o as s,c as d,ag as n}from"./chunks/framework.DEs8X8sU.js";const b=JSON.parse('{"title":"プラン・コース管理","description":"","frontmatter":{"feature_id":"PLAN-COURSE","title":"プラン・コース管理","chapter":10,"plan":["all"],"role":["owner","manager"],"audience":"店長以上","keywords":["食べ放題","コース","タイマー","フェーズ","時間制限","飲み放題","懐石","専用メニュー"],"related":["04-menu","06-orders","24-reservations"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"tenant/10-plans.md","filePath":"tenant/10-plans.md"}'),e={name:"tenant/10-plans.md"};function l(r,t,i,o,p,h){return s(),d("div",null,[...t[0]||(t[0]=[n(`<h1 id="_10-プラン・コース管理" tabindex="-1">10. プラン・コース管理 <a class="header-anchor" href="#_10-プラン・コース管理" aria-label="Permalink to &quot;10. プラン・コース管理&quot;">​</a></h1><p>管理ダッシュボード（<code>dashboard.html</code>）の「プラン・コース」タブでは、<strong>食べ放題プラン（時間制限付きプラン）</strong> と <strong>コース料理テンプレート</strong> を管理します。マネージャー以上のロールで利用できます。</p><div class="warning custom-block"><p class="custom-block-title">用語の混同に注意</p><p>本章で扱う「プラン」は <strong>飲食店のメニュープラン</strong>（食べ放題・飲み放題など）です。POSLA の <strong>サブスクリプション契約プラン</strong>（月額 ¥20,000 等、α-1 構成）とは別概念です。サブスクリプション側は 21 章を参照してください。</p></div><h2 id="_10-0-はじめにお読みください" tabindex="-1">10.0 はじめにお読みください <a class="header-anchor" href="#_10-0-はじめにお読みください" aria-label="Permalink to &quot;10.0 はじめにお読みください&quot;">​</a></h2><h3 id="_10-0-1-この章の読み方" tabindex="-1">10.0.1 この章の読み方 <a class="header-anchor" href="#_10-0-1-この章の読み方" aria-label="Permalink to &quot;10.0.1 この章の読み方&quot;">​</a></h3><table tabindex="0"><thead><tr><th>あなたの店舗</th><th>重点的に読む節</th></tr></thead><tbody><tr><td>食べ放題・飲み放題を提供している</td><td>10.1（食べ放題プラン）+ 10.4（運用）</td></tr><tr><td>コース料理（懐石・会席・コース盛り合わせ）を提供する</td><td>10.2（コース料理）+ 10.5（運用）</td></tr><tr><td>予約サイトからコース指定で来店受付したい</td><td>10.5.3（コース予約連携）+ 24 章</td></tr><tr><td>単品（アラカルト）のみで運用</td><td>本章は読み飛ばし可。04 章（メニュー）のみで完結</td></tr></tbody></table><h3 id="_10-0-2-「プラン」と「コース」の使い分け早見表" tabindex="-1">10.0.2 「プラン」と「コース」の使い分け早見表 <a class="header-anchor" href="#_10-0-2-「プラン」と「コース」の使い分け早見表" aria-label="Permalink to &quot;10.0.2 「プラン」と「コース」の使い分け早見表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>観点</th><th>プラン（time_limit_plans）</th><th>コース（course_templates）</th></tr></thead><tbody><tr><td>課金モデル</td><td><strong>時間内 食べ放題 / 飲み放題</strong>（定額）</td><td><strong>決まった料理セット</strong>（定額）</td></tr><tr><td>お客様の自由度</td><td>対象品目から自由に何度でも注文</td><td>順番・品目はお店が決める</td></tr><tr><td>時間制限</td><td>あり（90分等。LO 連動）</td><td>基本なし（推奨は 120 分以内）</td></tr><tr><td>KDS 表示</td><td>通常注文と同じ</td><td>フェーズごとに自動 / 手動投入</td></tr><tr><td>想定店舗</td><td>居酒屋、しゃぶしゃぶ、焼肉</td><td>懐石、会席、フレンチ、コース寿司</td></tr><tr><td>排他</td><td>同一テーブルでコースと同時不可</td><td>同一テーブルでプランと同時不可</td></tr></tbody></table><h3 id="_10-0-3-操作前のチェックリスト" tabindex="-1">10.0.3 操作前のチェックリスト <a class="header-anchor" href="#_10-0-3-操作前のチェックリスト" aria-label="Permalink to &quot;10.0.3 操作前のチェックリスト&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th><th>確認方法</th><th>NG 時の対応</th></tr></thead><tbody><tr><td>1</td><td>あなたのロールが manager 以上</td><td>画面右上 → ロール表示</td><td>owner に依頼</td></tr><tr><td>2</td><td>対象店舗が選択されている</td><td>dashboard 上部の店舗セレクタ</td><td>切替</td></tr><tr><td>3</td><td>カテゴリが事前に作成済み</td><td>04 章「カテゴリ管理」</td><td>先に 04 章でカテゴリ追加</td></tr><tr><td>4</td><td>KDS が起動している（運用テストする場合）</td><td>レジ・キッチンの KDS 画面</td><td>17 章「KDS」</td></tr><tr><td>5</td><td>テーブルが登録済み（ハンディから割当る場合）</td><td>dashboard「テーブル」タブ</td><td>先に「+ テーブル追加」</td></tr></tbody></table><hr><h2 id="_10-1-食べ放題プラン" tabindex="-1">10.1 食べ放題プラン <a class="header-anchor" href="#_10-1-食べ放題プラン" aria-label="Permalink to &quot;10.1 食べ放題プラン&quot;">​</a></h2><h3 id="_10-1-1-プラン一覧画面" tabindex="-1">10.1.1 プラン一覧画面 <a class="header-anchor" href="#_10-1-1-プラン一覧画面" aria-label="Permalink to &quot;10.1.1 プラン一覧画面&quot;">​</a></h3><p>「プラン・コース」タブ → <strong>「食べ放題プラン」</strong> サブタブを選択すると、登録済みプランの一覧が表示されます。</p><h4 id="表示要素一覧" tabindex="-1">表示要素一覧 <a class="header-anchor" href="#表示要素一覧" aria-label="Permalink to &quot;表示要素一覧&quot;">​</a></h4><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>プラン名</td><td>日本語名（英語名があればカッコ内に表示）</td></tr><tr><td>制限時間</td><td>「90分」形式</td></tr><tr><td>ラストオーダー</td><td>「LO 15分前」形式</td></tr><tr><td>価格</td><td>「¥2,980」形式（税込）</td></tr><tr><td>ステータスバッジ</td><td>緑色「有効」 / 赤色「無効」</td></tr><tr><td>並び順</td><td>表示順の数値（小さいほど上）</td></tr><tr><td>「メニュー管理」ボタン</td><td>プラン専用メニューの展開（10.1.4 へ）</td></tr><tr><td>「編集」ボタン</td><td>プランの編集モーダル</td></tr><tr><td>「削除」ボタン</td><td>プランの削除（DB から完全削除）</td></tr></tbody></table><h4 id="画面イメージ" tabindex="-1">画面イメージ <a class="header-anchor" href="#画面イメージ" aria-label="Permalink to &quot;画面イメージ&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────┐</span></span>
<span class="line"><span>│  プラン・コース  &gt;  食べ放題プラン         │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  [+ プラン追加]                            │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  ┌──────────────────────────────┐       │</span></span>
<span class="line"><span>│  │ 90分食べ放題（90min All-You）│       │</span></span>
<span class="line"><span>│  │ 90分 / LO 15分前 [有効]      │ ¥2,980│</span></span>
<span class="line"><span>│  │  [メニュー管理] [編集] [削除] │       │</span></span>
<span class="line"><span>│  └──────────────────────────────┘       │</span></span>
<span class="line"><span>│                                          │</span></span>
<span class="line"><span>│  ┌──────────────────────────────┐       │</span></span>
<span class="line"><span>│  │ ランチ食べ放題                │       │</span></span>
<span class="line"><span>│  │ 60分 / LO 10分前 [有効]      │ ¥1,500│</span></span>
<span class="line"><span>│  │  [メニュー管理] [編集] [削除] │       │</span></span>
<span class="line"><span>│  └──────────────────────────────┘       │</span></span>
<span class="line"><span>└──────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_10-1-2-プランの追加" tabindex="-1">10.1.2 プランの追加 <a class="header-anchor" href="#_10-1-2-プランの追加" aria-label="Permalink to &quot;10.1.2 プランの追加&quot;">​</a></h3><h4 id="操作前チェックリスト" tabindex="-1">操作前チェックリスト <a class="header-anchor" href="#操作前チェックリスト" aria-label="Permalink to &quot;操作前チェックリスト&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>提供時間帯（ランチ食べ放題かディナーか）を決めている</td></tr><tr><td>2</td><td>対象品目のリストアップ済み（後で 10.1.4 で登録）</td></tr><tr><td>3</td><td>価格・LO（ラストオーダー）何分前かが決まっている</td></tr></tbody></table><h4 id="クリック単位の操作手順" tabindex="-1">クリック単位の操作手順 <a class="header-anchor" href="#クリック単位の操作手順" aria-label="Permalink to &quot;クリック単位の操作手順&quot;">​</a></h4><ol><li>dashboard ログイン</li><li>上部タブから <strong>「プラン・コース」</strong> をクリック</li><li>サブタブ <strong>「食べ放題プラン」</strong> を選択</li><li>画面右上の <strong>「+ プラン追加」</strong> ボタンをクリック</li><li>モーダルダイアログが開きます</li><li>各フィールドに入力（10.1.3 表参照）</li><li>画面下部 <strong>「追加」</strong> ボタンをクリック</li><li>「プランを追加しました」とトースト通知</li><li>一覧に新規プランが追加される</li></ol><h4 id="_10-1-3-入力フィールドの詳細" tabindex="-1">10.1.3 入力フィールドの詳細 <a class="header-anchor" href="#_10-1-3-入力フィールドの詳細" aria-label="Permalink to &quot;10.1.3 入力フィールドの詳細&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>文字種・範囲</th><th>説明</th></tr></thead><tbody><tr><td>1</td><td>プラン名</td><td>テキスト</td><td>✅</td><td>—</td><td>全角OK、最大100文字</td><td>例：「90分食べ放題」</td></tr><tr><td>2</td><td>プラン名（英語）</td><td>テキスト</td><td>—</td><td>—</td><td>ASCII 推奨</td><td>例：「90min All-You-Can-Eat」</td></tr><tr><td>3</td><td>制限時間（分）</td><td>数値</td><td>✅</td><td>90</td><td>1〜480（8時間）</td><td>プランの時間制限</td></tr><tr><td>4</td><td>LO（終了N分前）</td><td>数値</td><td>—</td><td>15</td><td>0〜120</td><td>終了の何分前にラストオーダー扱いとするか</td></tr><tr><td>5</td><td>料金（税込）</td><td>数値</td><td>—</td><td>0</td><td>0〜999,999</td><td>プラン料金（人数分一括または1人分）</td></tr><tr><td>6</td><td>表示順</td><td>数値</td><td>—</td><td>0</td><td>-32,768〜32,767</td><td>小さいほど上</td></tr><tr><td>7</td><td>説明</td><td>テキストエリア</td><td>—</td><td>—</td><td>2行</td><td>プランの説明文</td></tr></tbody></table><h4 id="入力例ブロック" tabindex="-1">入力例ブロック <a class="header-anchor" href="#入力例ブロック" aria-label="Permalink to &quot;入力例ブロック&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>プラン名: しゃぶしゃぶ食べ放題 90分</span></span>
<span class="line"><span>プラン名（英語）: Shabu-Shabu 90min All You Can Eat</span></span>
<span class="line"><span>制限時間（分）: 90</span></span>
<span class="line"><span>LO（終了N分前）: 15</span></span>
<span class="line"><span>料金（税込）: 3800</span></span>
<span class="line"><span>表示順: 10</span></span>
<span class="line"><span>説明: 国産黒毛和牛のしゃぶしゃぶ食べ放題。野菜・締めの麺類も食べ放題対象。</span></span></code></pre></div><h3 id="_10-1-4-プランの編集" tabindex="-1">10.1.4 プランの編集 <a class="header-anchor" href="#_10-1-4-プランの編集" aria-label="Permalink to &quot;10.1.4 プランの編集&quot;">​</a></h3><p>既存プランの編集では、10.1.3 の項目に加えて以下が変更可能です。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>説明</th></tr></thead><tbody><tr><td>有効 / 無効</td><td>セレクト</td><td>無効にすると着席時のプラン選択肢から消える（既に適用中のセッションは維持）</td></tr></tbody></table><h4 id="操作手順" tabindex="-1">操作手順 <a class="header-anchor" href="#操作手順" aria-label="Permalink to &quot;操作手順&quot;">​</a></h4><ol><li>プラン一覧で対象プランの <strong>「編集」</strong> ボタンをクリック</li><li>モーダルに既存値が表示される</li><li>変更したいフィールドを修正</li><li><strong>「更新」</strong> ボタンをクリック</li><li>「プランを更新しました」とトースト</li></ol><div class="tip custom-block"><p class="custom-block-title">プラン無効化の使いどき</p><ul><li>季節限定プラン（夏季限定など）の終了</li><li>メニュー仕入れ都合で一時停止</li><li>料金改定の準備期間（旧プラン無効 → 新プラン作成）</li></ul></div><h3 id="_10-1-5-プラン専用メニュー-plan-menu-items" tabindex="-1">10.1.5 プラン専用メニュー（plan_menu_items） <a class="header-anchor" href="#_10-1-5-プラン専用メニュー-plan-menu-items" aria-label="Permalink to &quot;10.1.5 プラン専用メニュー（plan_menu_items）&quot;">​</a></h3><p>食べ放題プランには <strong>プラン専用の品目</strong> を登録できます。これらは通常メニュー（menu_templates）とは別管理で、プラン契約者だけが注文できます。</p><h4 id="専用メニューの表示・追加" tabindex="-1">専用メニューの表示・追加 <a class="header-anchor" href="#専用メニューの表示・追加" aria-label="Permalink to &quot;専用メニューの表示・追加&quot;">​</a></h4><ol><li>プラン一覧で対象プランの <strong>「メニュー管理」</strong> ボタンをクリック</li><li>ボタンが「閉じる」に変わり、プラン直下に専用メニュー一覧が展開</li><li><strong>「+ 品目追加」</strong> ボタンをクリック → モーダル</li></ol><h4 id="品目追加フォーム入力フィールド" tabindex="-1">品目追加フォーム入力フィールド <a class="header-anchor" href="#品目追加フォーム入力フィールド" aria-label="Permalink to &quot;品目追加フォーム入力フィールド&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>1</td><td>品目名</td><td>テキスト</td><td>✅</td><td>日本語名（例：「ビール」「ハイボール」）</td></tr><tr><td>2</td><td>品目名（英語）</td><td>テキスト</td><td>—</td><td>英語名</td></tr><tr><td>3</td><td>カテゴリ</td><td>セレクト</td><td>—</td><td>04 章のカテゴリから選択</td></tr><tr><td>4</td><td>説明</td><td>テキストエリア</td><td>—</td><td>2行</td></tr><tr><td>5</td><td>表示順</td><td>数値</td><td>—</td><td>0</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">入力例</p><ul><li>ビール（カテゴリ：ドリンク）</li><li>生中ジョッキ（カテゴリ：ドリンク）</li><li>ハイボール（カテゴリ：ドリンク）</li><li>レモンサワー（カテゴリ：ドリンク）</li></ul></div><h4 id="専用メニューの編集・削除" tabindex="-1">専用メニューの編集・削除 <a class="header-anchor" href="#専用メニューの編集・削除" aria-label="Permalink to &quot;専用メニューの編集・削除&quot;">​</a></h4><p>各品目行右側の <strong>「編集」</strong> / <strong>「削除」</strong> ボタンから操作。編集時は「表示」セレクトで「無効」にもできます（プラン適用中の品切れ運用に便利）。</p><hr><h2 id="_10-2-コース料理" tabindex="-1">10.2 コース料理 <a class="header-anchor" href="#_10-2-コース料理" aria-label="Permalink to &quot;10.2 コース料理&quot;">​</a></h2><h3 id="_10-2-1-コース一覧画面" tabindex="-1">10.2.1 コース一覧画面 <a class="header-anchor" href="#_10-2-1-コース一覧画面" aria-label="Permalink to &quot;10.2.1 コース一覧画面&quot;">​</a></h3><p>「プラン・コース」タブ → <strong>「コース管理」</strong> サブタブを選択すると、登録済みコースの一覧が表示されます。</p><h4 id="表示要素一覧-1" tabindex="-1">表示要素一覧 <a class="header-anchor" href="#表示要素一覧-1" aria-label="Permalink to &quot;表示要素一覧&quot;">​</a></h4><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>コース名</td><td>日本語名（英語名があればカッコ内）</td></tr><tr><td>フェーズ数</td><td>「3フェーズ」形式</td></tr><tr><td>価格</td><td>「¥5,000」形式（税込）</td></tr><tr><td>ステータスバッジ</td><td>有効 / 無効</td></tr><tr><td>説明</td><td>コースの説明文</td></tr><tr><td>フェーズ一覧</td><td>各フェーズが折り畳まずに表示</td></tr><tr><td>「+ フェーズ追加」</td><td>コース末尾に新規フェーズ</td></tr><tr><td>「編集」「削除」</td><td>各フェーズの操作</td></tr></tbody></table><h4 id="画面イメージ-松コース例" tabindex="-1">画面イメージ（松コース例） <a class="header-anchor" href="#画面イメージ-松コース例" aria-label="Permalink to &quot;画面イメージ（松コース例）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  プラン・コース  &gt;  コース管理              │</span></span>
<span class="line"><span>│                                            │</span></span>
<span class="line"><span>│  [+ コース追加]                              │</span></span>
<span class="line"><span>│                                            │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │ 松コース（Matsu Course） [有効]    │¥8000│</span></span>
<span class="line"><span>│  │ 3フェーズ                          │     │</span></span>
<span class="line"><span>│  │ 季節の懐石フルコース                │     │</span></span>
<span class="line"><span>│  │   [編集] [削除]                    │     │</span></span>
<span class="line"><span>│  │                                    │     │</span></span>
<span class="line"><span>│  │ ┌─[1]─前菜 [手動]──────────────┐ │     │</span></span>
<span class="line"><span>│  │ │  サラダ、スープ                │ │     │</span></span>
<span class="line"><span>│  │ │  [編集][削除]                  │ │     │</span></span>
<span class="line"><span>│  │ └────────────────────────────────┘ │     │</span></span>
<span class="line"><span>│  │ ┌─[2]─メイン [自動 15分後]─────┐ │     │</span></span>
<span class="line"><span>│  │ │  刺身盛り合わせ、天ぷら ×1    │ │     │</span></span>
<span class="line"><span>│  │ └────────────────────────────────┘ │     │</span></span>
<span class="line"><span>│  │ ┌─[3]─デザート [自動 20分後]──┐ │     │</span></span>
<span class="line"><span>│  │ │  抹茶アイス、コーヒー          │ │     │</span></span>
<span class="line"><span>│  │ └────────────────────────────────┘ │     │</span></span>
<span class="line"><span>│  │  [+ フェーズ追加]                  │     │</span></span>
<span class="line"><span>│  └──────────────────────────────────┘     │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_10-2-2-コースの追加" tabindex="-1">10.2.2 コースの追加 <a class="header-anchor" href="#_10-2-2-コースの追加" aria-label="Permalink to &quot;10.2.2 コースの追加&quot;">​</a></h3><h4 id="操作前チェックリスト-1" tabindex="-1">操作前チェックリスト <a class="header-anchor" href="#操作前チェックリスト-1" aria-label="Permalink to &quot;操作前チェックリスト&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th></tr></thead><tbody><tr><td>1</td><td>コースの全フェーズと提供順が決まっている</td></tr><tr><td>2</td><td>各フェーズの品目と数量がリストアップ済み</td></tr><tr><td>3</td><td>フェーズ間の自動進行 / 手動進行ポリシーを決めている</td></tr><tr><td>4</td><td>価格（一人前 or 一卓）が確定している</td></tr></tbody></table><h4 id="操作手順-1" tabindex="-1">操作手順 <a class="header-anchor" href="#操作手順-1" aria-label="Permalink to &quot;操作手順&quot;">​</a></h4><ol><li>dashboard &gt; プラン・コース &gt; <strong>「コース管理」</strong> サブタブ</li><li>右上 <strong>「+ コース追加」</strong> ボタン</li><li>モーダルが開く</li><li>入力フィールドに記入</li><li><strong>「追加」</strong> ボタン</li><li>「コースを追加しました」とトースト</li><li>一覧の末尾にコース行が追加される</li><li>続けて <strong>「+ フェーズ追加」</strong> で各フェーズを登録（10.2.3）</li></ol><h4 id="入力フィールドの詳細" tabindex="-1">入力フィールドの詳細 <a class="header-anchor" href="#入力フィールドの詳細" aria-label="Permalink to &quot;入力フィールドの詳細&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>1</td><td>コース名</td><td>テキスト</td><td>✅</td><td>—</td><td>例：「松コース」</td></tr><tr><td>2</td><td>コース名（英語）</td><td>テキスト</td><td>—</td><td>—</td><td>例：「Matsu Course」</td></tr><tr><td>3</td><td>料金（税込）</td><td>数値</td><td>—</td><td>0</td><td>コース料金（人数分一括または1人分）</td></tr><tr><td>4</td><td>表示順</td><td>数値</td><td>—</td><td>0</td><td>一覧上の順番</td></tr><tr><td>5</td><td>説明</td><td>テキストエリア</td><td>—</td><td>—</td><td>2行</td></tr></tbody></table><h3 id="_10-2-3-フェーズの追加" tabindex="-1">10.2.3 フェーズの追加 <a class="header-anchor" href="#_10-2-3-フェーズの追加" aria-label="Permalink to &quot;10.2.3 フェーズの追加&quot;">​</a></h3><p>コース料理は <strong>フェーズ（段階）</strong> で構成されます。各フェーズは順番に提供される料理のグループです。</p><h4 id="操作手順-2" tabindex="-1">操作手順 <a class="header-anchor" href="#操作手順-2" aria-label="Permalink to &quot;操作手順&quot;">​</a></h4><ol><li>コース一覧の対象コースの <strong>「+ フェーズ追加」</strong> ボタン</li><li>モーダルが開く</li><li>入力フィールドに記入</li><li><strong>「追加」</strong> ボタン</li><li>フェーズ番号は自動的に <strong>連番</strong>（既存最大 +1）で付与される</li></ol><h4 id="入力フィールドの詳細-1" tabindex="-1">入力フィールドの詳細 <a class="header-anchor" href="#入力フィールドの詳細-1" aria-label="Permalink to &quot;入力フィールドの詳細&quot;">​</a></h4><table tabindex="0"><thead><tr><th>#</th><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>1</td><td>フェーズ名</td><td>テキスト</td><td>✅</td><td>例：「前菜」「メイン」「デザート」</td></tr><tr><td>2</td><td>フェーズ名（英語）</td><td>テキスト</td><td>—</td><td>例：「Appetizer」</td></tr><tr><td>3</td><td>自動発火（前フェーズ完了後N分）</td><td>数値</td><td>—</td><td>空欄＝手動。値あり＝N分後に自動投入</td></tr><tr><td>4</td><td>品目</td><td>テキストエリア</td><td>✅</td><td>1行に1品目（10.2.4 参照）</td></tr></tbody></table><h4 id="_10-2-4-品目の入力形式" tabindex="-1">10.2.4 品目の入力形式 <a class="header-anchor" href="#_10-2-4-品目の入力形式" aria-label="Permalink to &quot;10.2.4 品目の入力形式&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>サラダ</span></span>
<span class="line"><span>スープ ×2</span></span>
<span class="line"><span>刺身盛り合わせ ×1</span></span></code></pre></div><h5 id="パース規則" tabindex="-1">パース規則 <a class="header-anchor" href="#パース規則" aria-label="Permalink to &quot;パース規則&quot;">​</a></h5><ul><li><strong>数量を省略した場合は 1</strong> として扱われます</li><li><strong><code>×</code></strong>（全角ばつ）と <strong><code>x</code></strong>（半角エックス）どちらも使用可能</li><li>1行が空白のみなら無視</li><li>品目名と数量の間にスペース必須（<code>サラダ×2</code> ではなく <code>サラダ ×2</code>）</li><li>数量は半角整数のみ（<code>サラダ ×二</code> は弾かれる）</li></ul><h5 id="入力例ブロック-1" tabindex="-1">入力例ブロック <a class="header-anchor" href="#入力例ブロック-1" aria-label="Permalink to &quot;入力例ブロック&quot;">​</a></h5><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先付け盛り合わせ</span></span>
<span class="line"><span>お椀（季節の汁物）</span></span>
<span class="line"><span>お造り 三種盛り ×1</span></span>
<span class="line"><span>焼物 季節魚 ×1</span></span>
<span class="line"><span>天ぷら 五種 ×1</span></span>
<span class="line"><span>ご飯</span></span>
<span class="line"><span>香の物</span></span>
<span class="line"><span>水菓子</span></span></code></pre></div><h3 id="_10-2-5-フェーズの発火方式" tabindex="-1">10.2.5 フェーズの発火方式 <a class="header-anchor" href="#_10-2-5-フェーズの発火方式" aria-label="Permalink to &quot;10.2.5 フェーズの発火方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>表示</th><th>動作</th></tr></thead><tbody><tr><td>手動</td><td>バッジ「手動」</td><td>KDS 画面の「次フェーズ」ボタンで進める</td></tr><tr><td>自動</td><td>バッジ「自動 N分後」</td><td>前のフェーズ開始からN分後に自動で次のフェーズの料理が KDS に表示される</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">発火方式の選び方</p><ul><li><strong>回転率重視（居酒屋・大衆向け）</strong>: 自動進行（10〜15 分間隔）</li><li><strong>高級店・お客様のペース重視</strong>: 手動進行</li><li><strong>混合</strong>: フェーズ1（前菜）は手動、フェーズ2以降は自動 など</li></ul></div><h3 id="_10-2-6-フェーズの編集" tabindex="-1">10.2.6 フェーズの編集 <a class="header-anchor" href="#_10-2-6-フェーズの編集" aria-label="Permalink to &quot;10.2.6 フェーズの編集&quot;">​</a></h3><p>各フェーズの <strong>「編集」</strong> ボタンから 10.2.3 と同じモーダルで変更可能。</p><div class="warning custom-block"><p class="custom-block-title">フェーズ番号の変更は要注意</p><p>モーダル内では <code>phase_number</code> の直接編集 UI は非表示（API は対応）。フェーズの並び替えは現状「削除して再追加」が推奨です。</p></div><h3 id="_10-2-7-フェーズの削除" tabindex="-1">10.2.7 フェーズの削除 <a class="header-anchor" href="#_10-2-7-フェーズの削除" aria-label="Permalink to &quot;10.2.7 フェーズの削除&quot;">​</a></h3><p>各フェーズの <strong>「削除」</strong> ボタン → 確認ダイアログ → <strong>「OK」</strong>。</p><p>削除後、<code>course_templates.phase_count</code> が自動で再カウント（残フェーズ数）されます。</p><div class="warning custom-block"><p class="custom-block-title">コース削除時の注意</p><p>コースを削除すると、そのコースに紐づく <strong>全てのフェーズも削除されます</strong>（カスケード削除）。</p></div><hr><h2 id="_10-3-着席時のプラン・コース選択" tabindex="-1">10.3 着席時のプラン・コース選択 <a class="header-anchor" href="#_10-3-着席時のプラン・コース選択" aria-label="Permalink to &quot;10.3 着席時のプラン・コース選択&quot;">​</a></h2><h3 id="_10-3-1-ハンディからの割当" tabindex="-1">10.3.1 ハンディからの割当 <a class="header-anchor" href="#_10-3-1-ハンディからの割当" aria-label="Permalink to &quot;10.3.1 ハンディからの割当&quot;">​</a></h3><h4 id="前提" tabindex="-1">前提 <a class="header-anchor" href="#前提" aria-label="Permalink to &quot;前提&quot;">​</a></h4><ul><li>ハンディ（<code>/public/handy/index.html</code>）に device アカウント or staff/manager でログイン</li><li>対象店舗の GPS 圏内（device は強制 GPS チェック）</li></ul><h4 id="操作手順-3" tabindex="-1">操作手順 <a class="header-anchor" href="#操作手順-3" aria-label="Permalink to &quot;操作手順&quot;">​</a></h4><ol><li>ハンディトップ → <strong>「テーブル状況」</strong> タブ</li><li>着席させたいテーブルをタップ</li><li><strong>「着席」</strong> ボタンをタップ</li><li>着席モーダルが開く</li><li><strong>人数入力</strong> + <strong>プラン or コース選択</strong>（プルダウン）</li><li><strong>「着席を確定」</strong> をタップ</li></ol><h4 id="着席モーダル-ascii" tabindex="-1">着席モーダル ASCII <a class="header-anchor" href="#着席モーダル-ascii" aria-label="Permalink to &quot;着席モーダル ASCII&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  T-12 着席登録           │</span></span>
<span class="line"><span>│                         │</span></span>
<span class="line"><span>│  人数: [ 4 ] 人           │</span></span>
<span class="line"><span>│                         │</span></span>
<span class="line"><span>│  プラン:                  │</span></span>
<span class="line"><span>│  ┌──────────────────┐  │</span></span>
<span class="line"><span>│  │ なし（アラカルト）   ▼│  │</span></span>
<span class="line"><span>│  │ 90分食べ放題          │  │</span></span>
<span class="line"><span>│  │ ランチ食べ放題         │  │</span></span>
<span class="line"><span>│  └──────────────────┘  │</span></span>
<span class="line"><span>│                         │</span></span>
<span class="line"><span>│  コース:                  │</span></span>
<span class="line"><span>│  ┌──────────────────┐  │</span></span>
<span class="line"><span>│  │ なし                  ▼│  │</span></span>
<span class="line"><span>│  │ 松コース ¥8,000      │  │</span></span>
<span class="line"><span>│  │ 竹コース ¥5,000      │  │</span></span>
<span class="line"><span>│  └──────────────────┘  │</span></span>
<span class="line"><span>│                         │</span></span>
<span class="line"><span>│  [キャンセル] [着席を確定]│</span></span>
<span class="line"><span>└─────────────────────────┘</span></span></code></pre></div><h3 id="_10-3-2-セルフメニュー側の表示" tabindex="-1">10.3.2 セルフメニュー側の表示 <a class="header-anchor" href="#_10-3-2-セルフメニュー側の表示" aria-label="Permalink to &quot;10.3.2 セルフメニュー側の表示&quot;">​</a></h3><p>お客様が QR スキャンで開く <code>menu.html</code> 側では、着席時に設定されたプラン・コース情報が以下のように反映されます。</p><table tabindex="0"><thead><tr><th>種類</th><th>お客様画面での表示</th></tr></thead><tbody><tr><td>プラン適用</td><td>プラン対象品目は <strong>¥0</strong> で表示。プラン外品目は通常価格</td></tr><tr><td>コース適用</td><td>フェーズ進行を上部バナーで表示。「現在 1/3 フェーズ：前菜」</td></tr><tr><td>LO アラート</td><td>プラン LO 時刻に達すると「ラストオーダーまで残り N 分」バナー</td></tr><tr><td>プラン時間タイマー</td><td>残り時間の常時表示（緑→黄→赤）</td></tr></tbody></table><h3 id="_10-3-3-排他制御" tabindex="-1">10.3.3 排他制御 <a class="header-anchor" href="#_10-3-3-排他制御" aria-label="Permalink to &quot;10.3.3 排他制御&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">プランとコースは同テーブル同時不可</p><p>1 つのテーブルセッションに <strong>プランとコースの両方</strong> を設定することはできません。同じグループ内でプランの人とコースの人を分けたい場合は以下のいずれか：</p><ul><li><strong>別テーブル</strong> に分かれて着席</li><li><strong>サブセッション</strong>（F-QR1 / sub-sessions）で 1 テーブルを論理分割</li></ul></div><hr><h2 id="_10-4-食べ放題プランの運用" tabindex="-1">10.4 食べ放題プランの運用 <a class="header-anchor" href="#_10-4-食べ放題プランの運用" aria-label="Permalink to &quot;10.4 食べ放題プランの運用&quot;">​</a></h2><h3 id="_10-4-1-想定運用例" tabindex="-1">10.4.1 想定運用例 <a class="header-anchor" href="#_10-4-1-想定運用例" aria-label="Permalink to &quot;10.4.1 想定運用例&quot;">​</a></h3><h4 id="ケース-1-居酒屋の飲み放題" tabindex="-1">ケース 1：居酒屋の飲み放題 <a class="header-anchor" href="#ケース-1-居酒屋の飲み放題" aria-label="Permalink to &quot;ケース 1：居酒屋の飲み放題&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>値</th></tr></thead><tbody><tr><td>プラン名</td><td>「飲み放題 2 時間 ¥1,500」</td></tr><tr><td>制限時間</td><td>120 分</td></tr><tr><td>LO</td><td>15 分前</td></tr><tr><td>営業時間帯</td><td>18:00 〜 23:00（ランチ別プラン）</td></tr><tr><td>対象品目（plan_menu_items）</td><td>ドリンクカテゴリ全品（生ビール、ハイボール、サワー、ワイン、ソフトドリンク 等）</td></tr><tr><td>価格</td><td>¥1,500</td></tr></tbody></table><h4 id="ケース-2-しゃぶしゃぶ食べ放題" tabindex="-1">ケース 2：しゃぶしゃぶ食べ放題 <a class="header-anchor" href="#ケース-2-しゃぶしゃぶ食べ放題" aria-label="Permalink to &quot;ケース 2：しゃぶしゃぶ食べ放題&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>値</th></tr></thead><tbody><tr><td>プラン名</td><td>「しゃぶしゃぶ食べ放題 90 分 ¥3,800」</td></tr><tr><td>制限時間</td><td>90 分</td></tr><tr><td>LO</td><td>15 分前</td></tr><tr><td>営業時間帯</td><td>16:00 〜 21:00</td></tr><tr><td>対象品目</td><td>肉・野菜・締め麺類カテゴリ</td></tr><tr><td>価格</td><td>¥3,800（大人）</td></tr></tbody></table><h4 id="ケース-3-ランチ食べ放題" tabindex="-1">ケース 3：ランチ食べ放題 <a class="header-anchor" href="#ケース-3-ランチ食べ放題" aria-label="Permalink to &quot;ケース 3：ランチ食べ放題&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>値</th></tr></thead><tbody><tr><td>プラン名</td><td>「ランチビュッフェ 60 分 ¥1,200」</td></tr><tr><td>制限時間</td><td>60 分</td></tr><tr><td>LO</td><td>10 分前</td></tr><tr><td>営業時間帯</td><td>11:30 〜 14:30</td></tr><tr><td>対象品目</td><td>サラダ、スープ、メイン、ドリンク（アルコール除く）</td></tr></tbody></table><h3 id="_10-4-2-プラン適用のタイミング" tabindex="-1">10.4.2 プラン適用のタイミング <a class="header-anchor" href="#_10-4-2-プラン適用のタイミング" aria-label="Permalink to &quot;10.4.2 プラン適用のタイミング&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[着席]</span></span>
<span class="line"><span>   ↓ ハンディから「90分食べ放題」を選択</span></span>
<span class="line"><span>[セッション開始 18:00]</span></span>
<span class="line"><span>   ↓ time_limit_plans + table_sessions.plan_id 紐付け</span></span>
<span class="line"><span>[お客様セルフメニュー]</span></span>
<span class="line"><span>   ↓ プラン対象品目は ¥0 表示、プラン外は通常価格</span></span>
<span class="line"><span>[注文 → KDS → 提供] (回数無制限)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[19:30 LO アラート発火]（90 - 15 = 75 分経過時点）</span></span>
<span class="line"><span>   ↓ セルフメニュー上部に「ラストオーダー」バナー</span></span>
<span class="line"><span>[19:45 プラン終了 = 注文不可]</span></span>
<span class="line"><span>   ↓ 新規カート追加ボタンが disabled</span></span>
<span class="line"><span>[20:00 退店]</span></span>
<span class="line"><span>   ↓ POS レジで会計</span></span>
<span class="line"><span>[請求] = プラン料金 × 人数 + プラン外注文（通常価格）</span></span></code></pre></div><h3 id="_10-4-3-プラン時間管理" tabindex="-1">10.4.3 プラン時間管理 <a class="header-anchor" href="#_10-4-3-プラン時間管理" aria-label="Permalink to &quot;10.4.3 プラン時間管理&quot;">​</a></h3><ul><li>開始時刻：テーブルセッション開始時刻（着席ボタン押下時刻）</li><li>終了時刻：開始 + プラン時間（<code>duration_min</code>）</li><li>ハンディ「テーブル状況」で <strong>残り時間が常時表示</strong>（色変化） <ul><li>残り 30 分以上：緑</li><li>残り 10〜30 分：黄</li><li>残り 10 分以下：赤</li></ul></li><li>LO 時刻に達するとセルフメニューで <strong>ラストオーダーアラート</strong></li><li>LO 後の追加注文は API 側で <code>LAST_ORDER_PASSED</code> エラー返却</li></ul><h3 id="_10-4-4-アラカルト追加-プラン外注文" tabindex="-1">10.4.4 アラカルト追加（プラン外注文） <a class="header-anchor" href="#_10-4-4-アラカルト追加-プラン外注文" aria-label="Permalink to &quot;10.4.4 アラカルト追加（プラン外注文）&quot;">​</a></h3><p>プラン中でもプラン対象外の品目（特別メニュー・追加ドリンク等）は通常価格で注文可能。</p><ul><li>セルフメニューでプラン外品目を表示</li><li>通常カートに追加 → 通常価格で会計</li><li>KDS 側ではプラン注文と同じレーンに表示</li></ul><hr><h2 id="_10-5-コース料理の運用" tabindex="-1">10.5 コース料理の運用 <a class="header-anchor" href="#_10-5-コース料理の運用" aria-label="Permalink to &quot;10.5 コース料理の運用&quot;">​</a></h2><h3 id="_10-5-1-想定運用例-懐石コース-¥8-000" tabindex="-1">10.5.1 想定運用例：懐石コース ¥8,000 <a class="header-anchor" href="#_10-5-1-想定運用例-懐石コース-¥8-000" aria-label="Permalink to &quot;10.5.1 想定運用例：懐石コース ¥8,000&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フェーズ</th><th>名称</th><th>自動発火</th><th>主な品目</th></tr></thead><tbody><tr><td>1</td><td>先付け（前菜）</td><td>手動</td><td>季節の前菜盛り合わせ、お椀</td></tr><tr><td>2</td><td>お造り</td><td>自動 10 分後</td><td>三種盛り、あしらい</td></tr><tr><td>3</td><td>焼物</td><td>自動 15 分後</td><td>季節魚塩焼き</td></tr><tr><td>4</td><td>揚物</td><td>自動 15 分後</td><td>天ぷら五種</td></tr><tr><td>5</td><td>〆（食事）</td><td>自動 15 分後</td><td>季節炊き込みご飯、汁物、香の物</td></tr><tr><td>6</td><td>水菓子</td><td>自動 10 分後</td><td>季節フルーツ、抹茶アイス</td></tr></tbody></table><h3 id="_10-5-2-自動進行-vs-手動進行" tabindex="-1">10.5.2 自動進行 vs 手動進行 <a class="header-anchor" href="#_10-5-2-自動進行-vs-手動進行" aria-label="Permalink to &quot;10.5.2 自動進行 vs 手動進行&quot;">​</a></h3><table tabindex="0"><thead><tr><th>モード</th><th>動作</th><th>想定店舗</th></tr></thead><tbody><tr><td><strong>自動進行</strong></td><td>現フェーズ全品 served → <code>auto_fire_min</code> 経過 → 次フェーズ自動投入</td><td>標準コース、回転率重視</td></tr><tr><td><strong>手動進行</strong></td><td>KDS の「次フェーズ」ボタン押下まで待機</td><td>高級店、お客様のペースに合わせる</td></tr></tbody></table><h3 id="_10-5-3-コース予約との連携" tabindex="-1">10.5.3 コース予約との連携 <a class="header-anchor" href="#_10-5-3-コース予約との連携" aria-label="Permalink to &quot;10.5.3 コース予約との連携&quot;">​</a></h3><p>予約 LP（24 章）でお客様がコースを選んで予約 → 来店時に自動でテーブルにコース割当 → セッション開始でフェーズ 1 自動投入。</p><p>詳細フロー：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[予約 LP] お客様: 松コース ×4名 / 18:00</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[POSLA reservations テーブル: course_id 紐付け]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[来店日 17:50 リマインド SMS / LINE 自動送信]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[18:00 来店 → ホールスタッフがハンディで「予約から着席」]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[table_sessions.course_id 自動セット]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[フェーズ 1 自動 KDS 投入]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[KDS でフェーズ 1 全品 served → auto_fire_min 経過 → フェーズ 2 投入]</span></span></code></pre></div><h3 id="_10-5-4-kds-側の操作" tabindex="-1">10.5.4 KDS 側の操作 <a class="header-anchor" href="#_10-5-4-kds-側の操作" aria-label="Permalink to &quot;10.5.4 KDS 側の操作&quot;">​</a></h3><p>詳細は 17 章「KDS」参照。要点のみ：</p><ul><li>各フェーズの料理が <strong>同じテーブル番号 + フェーズ番号</strong> で表示</li><li>全品 <code>served</code> ボタン → 自動進行モードならカウントダウン開始</li><li>手動モードなら <strong>「次フェーズ」</strong> ボタンで明示的に進行</li><li>途中の特定品目を <strong>「取消」</strong> すると <code>cancelled</code> 扱い、フェーズ進行には影響なし（アレルギー対応等）</li></ul><hr><h2 id="_10-6-csv-インポート-エクスポート" tabindex="-1">10.6 CSV インポート / エクスポート <a class="header-anchor" href="#_10-6-csv-インポート-エクスポート" aria-label="Permalink to &quot;10.6 CSV インポート / エクスポート&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>エンドポイント</th></tr></thead><tbody><tr><td>プラン CSV エクスポート / インポート</td><td><code>GET/POST /api/store/time-limit-plans-csv.php</code></td></tr><tr><td>プラン専用品目 CSV</td><td><code>GET/POST /api/store/plan-menu-items-csv.php</code></td></tr><tr><td>コース CSV（コース + フェーズ統合）</td><td><code>GET/POST /api/store/course-csv.php</code></td></tr></tbody></table><h3 id="入出力ファイル形式-プラン" tabindex="-1">入出力ファイル形式（プラン） <a class="header-anchor" href="#入出力ファイル形式-プラン" aria-label="Permalink to &quot;入出力ファイル形式（プラン）&quot;">​</a></h3><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name_en,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">duration_min,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">last_order_min,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">price,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">sort_order,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">description,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">is_active</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">90分食べ放題,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">90min All,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">90,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">15,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">2980,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">10,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">90分食べ放題プラン,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ランチ食べ放題,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Lunch All,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">60,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">10,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1500,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">20,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ランチビュッフェ,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">大量初期データ投入のとき</p><p>20 件以上のプランを一気に登録する場合は CSV インポートが圧倒的に速いです。dashboard 上の「CSV インポート」ボタンから操作。</p></div><hr><h2 id="_10-x-よくある質問-faq" tabindex="-1">10.X よくある質問（FAQ） <a class="header-anchor" href="#_10-x-よくある質問-faq" aria-label="Permalink to &quot;10.X よくある質問（FAQ）&quot;">​</a></h2><h3 id="q1〜q5-概念・違い" tabindex="-1">Q1〜Q5: 概念・違い <a class="header-anchor" href="#q1〜q5-概念・違い" aria-label="Permalink to &quot;Q1〜Q5: 概念・違い&quot;">​</a></h3><p><strong>Q1. プランとコースの違い</strong></p><p>A. <strong>プラン</strong> は時間制（食べ放題 90 分等）、お客様が好きな品目を何度でも選べる。<strong>コース</strong> は料理セット（前菜→メイン→デザート）、決まった順番で料理が出る。両者は table_sessions レベルで排他。</p><p><strong>Q2. 1 つのテーブルにプランとコース両方は使える？</strong></p><p>A. <strong>不可</strong>。排他選択です。同じグループでもプランの人とコースの人を同席させたい場合は <strong>別テーブル</strong> にするか、<strong>サブセッション</strong>（F-QR1）で分割。</p><p><strong>Q3. 飲み放題と食べ放題を別プランにすべき？</strong></p><p>A. ケースバイケース。同価格・同時間なら 1 プランで対象品目に両方含める。価格や時間が異なる場合は 2 プラン作成して、お客様が選択。</p><p><strong>Q4. プランの時間は人数で延長される？</strong></p><p>A. 自動延長はされません。プラン時間は 1 セッション一律。人数で時間が変わる運用なら、人数別プランを複数登録（例：「2 名様 90 分」「4 名様 120 分」）。</p><p><strong>Q5. コースのフェーズ数に上限はある？</strong></p><p>A. DB 上は無制限ですが、運用上は 6〜8 フェーズが現実的です。10 を超えると KDS の表示が窮屈になります。</p><h3 id="q6〜q10-プラン運用" tabindex="-1">Q6〜Q10: プラン運用 <a class="header-anchor" href="#q6〜q10-プラン運用" aria-label="Permalink to &quot;Q6〜Q10: プラン運用&quot;">​</a></h3><p><strong>Q6. プラン時間延長したい</strong></p><p>A. ハンディの該当テーブル → <strong>【メモ編集】</strong> → プラン情報修正（DB 直接更新）。または管理画面でセッションメモ修正。次バージョンで「+15 分延長」専用ボタン予定。</p><p><strong>Q7. プラン時間が過ぎたら自動で会計？</strong></p><p>A. 自動会計はしない。スタッフが手動でラストオーダーを促す or 退店時に POS レジで会計。</p><p><strong>Q8. プラン料金はどう計算される？</strong></p><p>A. プラン料金は固定（例：大人 ¥3,800）。テーブルにプラン設定 + 人数指定で <code>プラン料金 × 人数</code> が会計に追加される。</p><p><strong>Q9. プラン途中で追加注文（アラカルト）</strong></p><p>A. プラン外として別カート行で追加可。プラン対象外なので通常価格で会計。</p><p><strong>Q10. プラン対象品目の指定方法は？</strong></p><p>A. プラン編集画面の <strong>「メニュー管理」</strong> ボタン → プラン専用メニュー（plan_menu_items）に登録。ここに登録された品目だけがプラン中に ¥0 表示される。</p><h3 id="q11〜q15-コース運用" tabindex="-1">Q11〜Q15: コース運用 <a class="header-anchor" href="#q11〜q15-コース運用" aria-label="Permalink to &quot;Q11〜Q15: コース運用&quot;">​</a></h3><p><strong>Q11. コースフェーズの自動進行条件</strong></p><p>A. 各フェーズ全品目が <code>served</code> になり、<code>auto_fire_min</code>（例：15 分）経過したら自動的に次フェーズへ。手動進行モードならボタンを押すまで進まない。</p><p><strong>Q12. コースの途中で 1 品だけ抜きたい（アレルギー対応）</strong></p><p>A. KDS で該当品目を <strong>【取消】</strong> ボタン → <code>cancelled</code> 扱い。次フェーズには進む。</p><p><strong>Q13. コース途中でフェーズ順を入れ替えたい（緊急対応）</strong></p><p>A. KDS の「次フェーズ」ボタンで強制進行可能。<code>auto_fire_min</code> を待たずに進めれる。</p><p><strong>Q14. 複数テーブルで同じコースを並行進行できる？</strong></p><p>A. 可能。各テーブルセッションが独立して進行する。KDS は店舗全体のフェーズ状況を一覧表示。</p><p><strong>Q15. コース価格は人数 × 1 名分？それとも一卓？</strong></p><p>A. POSLA の標準は <strong>人数 × 1 名分</strong>。一卓固定にしたいなら、フェーズ品目側で「人数分まとめ」として登録するワークアラウンドあり。</p><h3 id="q16〜q20-レポート・売上" tabindex="-1">Q16〜Q20: レポート・売上 <a class="header-anchor" href="#q16〜q20-レポート・売上" aria-label="Permalink to &quot;Q16〜Q20: レポート・売上&quot;">​</a></h3><p><strong>Q16. プランやコースの売上はレポートに出る？</strong></p><p>A. 出る。13 章 13.2 商品別ランキングで「プラン売上」「コース売上」として集計。</p><p><strong>Q17. プラン適用時、注文された ¥0 品目はレポートでカウントされる？</strong></p><p>A. カウントされる（数量のみ。金額は ¥0）。プラン消費量の分析に使える。</p><p><strong>Q18. コースの全フェーズが完了したかどうかは記録される？</strong></p><p>A. <code>table_sessions.current_phase_number</code> で現フェーズが記録される。退店時に <code>current_phase_number == phase_count</code> なら全完了。</p><p><strong>Q19. 食べ放題で人気の品目を分析したい</strong></p><p>A. 13 章「商品別ランキング」で <code>plan_id</code> 絞り込み機能を使う（次バージョン予定。現状は CSV エクスポート → Excel 集計）。</p><p><strong>Q20. プラン売上 / コース売上の月次比較</strong></p><p>A. 13 章「期間比較」で前月との比較可能。コース別・プラン別の絞り込みは Q19 と同様、CSV ベース。</p><h3 id="q21〜q25-連携・予約" tabindex="-1">Q21〜Q25: 連携・予約 <a class="header-anchor" href="#q21〜q25-連携・予約" aria-label="Permalink to &quot;Q21〜Q25: 連携・予約&quot;">​</a></h3><p><strong>Q21. 予約サイト経由でコース予約を受けたい</strong></p><p>A. 24 章「予約管理」のコース連携を使う。予約時にコース選択 → 来店時に自動セット。</p><p><strong>Q22. 食べ放題の人数を後から変更したい</strong></p><p>A. ハンディから着席セッション編集で人数変更可。プラン料金は人数 × 単価で再計算される。</p><p><strong>Q23. プラン中の途中追加（19:30 着席が 20:00 に 1 名追加）</strong></p><p>A. ハンディからセッションの人数変更。追加分のプラン料金が会計に上乗せ（プラン時間は元の終了時刻のまま、追加メンバーは短い時間しか使えない）。</p><p><strong>Q24. ハッピーアワー（時間帯別プラン価格）</strong></p><p>A. 現状は 1 プラン = 1 価格固定。ハッピーアワー対応は別プラン（「ハッピーアワー食べ放題 16-18 時 ¥1,000」）を作成して使い分ける。</p><p><strong>Q25. コース予約でフェーズの自動投入を遅らせたい（料理人準備時間）</strong></p><p>A. フェーズ 1 の <code>auto_fire_min</code> を 5 分等に設定し、着席時にすぐ投入されないようにする（現状は仕様上 0 分扱いなのでカスタマイズ要相談）。</p><h3 id="q26〜q28-設計・将来" tabindex="-1">Q26〜Q28: 設計・将来 <a class="header-anchor" href="#q26〜q28-設計・将来" aria-label="Permalink to &quot;Q26〜Q28: 設計・将来&quot;">​</a></h3><p><strong>Q26. プランやコースの英語名はいつ表示される？</strong></p><p>A. セルフメニューの言語切替で英語に切り替えると表示。ハンディ・KDS は基本日本語。</p><p><strong>Q27. 将来追加予定の機能</strong></p><p>A.</p><ul><li>プラン延長専用ボタン（+15 分 / +30 分）</li><li>コースフェーズの並び替え UI（現状は削除→再追加が必要）</li><li>プラン売上の専用ダッシュボード</li><li>多言語対応（英語以外：中国語・韓国語）</li></ul><p><strong>Q28. プランやコースを廃止したい</strong></p><p>A. 削除ボタンで物理削除可能。ただし過去のセッションで使われた <code>plan_id</code> / <code>course_id</code> は履歴として残るので、レポート上は引き続き集計される。</p><hr><h2 id="_10-y-トラブルシューティング" tabindex="-1">10.Y トラブルシューティング <a class="header-anchor" href="#_10-y-トラブルシューティング" aria-label="Permalink to &quot;10.Y トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>プランが選択肢に出ない</td><td>プランが <code>is_active=0</code></td><td>プラン編集で「有効」トグル ON</td></tr><tr><td>プラン時間が表示されない</td><td>テーブルにプラン未設定</td><td>ハンディからプラン設定</td></tr><tr><td>コース料理がフェーズ進まない</td><td>全品 <code>served</code> にしてない / <code>auto_fire_min</code> 未経過</td><td>KDS で全品 <code>served</code> にする or 「次フェーズ」ボタン</td></tr><tr><td>時間超過しても料金変わらない</td><td>仕様</td><td>別途精算（手動でアラカルト追加）</td></tr><tr><td>プランで¥0の品目が金額計上された</td><td>プラン専用品目（plan_menu_items）に未登録</td><td>プラン編集 → 「メニュー管理」で品目追加</td></tr><tr><td>コース内の特定品目が出ない</td><td>品切れ</td><td>在庫確認 + 代替品目の設定</td></tr><tr><td>プラン専用品目がセルフメニューに出ない</td><td>プラン未適用のテーブル</td><td>着席時にプラン選択</td></tr><tr><td>コース追加で「migration_required」エラー</td><td>DB マイグレーション未適用</td><td><code>sql/migration-*.sql</code> を運営に依頼</td></tr><tr><td>フェーズ品目入力で ×3 が認識されない</td><td>全角/半角混在、スペース欠落</td><td><code>品名 ×3</code> の形式（前後半角スペース）</td></tr><tr><td>プラン料金が会計に乗らない</td><td>人数未入力</td><td>着席モーダルで人数入力</td></tr><tr><td>コース予約から自動着席にならない</td><td>予約と着席店舗の不一致</td><td>予約時の店舗 ID を確認</td></tr><tr><td>LO アラートが出ない</td><td>LO 時刻計算ロジックの異常</td><td>サーバー時刻と店舗 timezone の整合性確認</td></tr></tbody></table><hr><h2 id="_10-z-技術補足" tabindex="-1">10.Z 技術補足 <a class="header-anchor" href="#_10-z-技術補足" aria-label="Permalink to &quot;10.Z 技術補足&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">通常テナントは読まなくて OK</p><h3 id="db-テーブル" tabindex="-1">DB テーブル <a class="header-anchor" href="#db-テーブル" aria-label="Permalink to &quot;DB テーブル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>テーブル</th><th>説明</th></tr></thead><tbody><tr><td><code>time_limit_plans</code></td><td>食べ放題プランマスタ（store 単位、価格・時間）</td></tr><tr><td><code>plan_menu_items</code></td><td>プラン専用品目（plan_id × 品目名 × カテゴリ）</td></tr><tr><td><code>course_templates</code></td><td>コーステンプレート（store 単位）</td></tr><tr><td><code>course_phases</code></td><td>コースのフェーズ定義（course_id × phase_number、<code>auto_fire_min</code> 含む、<code>items</code> は JSON 配列）</td></tr><tr><td><code>table_sessions.plan_id</code></td><td>テーブル別の適用プラン</td></tr><tr><td><code>table_sessions.course_id</code></td><td>テーブル別の適用コース</td></tr><tr><td><code>table_sessions.current_phase_number</code></td><td>現フェーズ番号（コース進行中）</td></tr></tbody></table><h3 id="api-エンドポイント" tabindex="-1">API エンドポイント <a class="header-anchor" href="#api-エンドポイント" aria-label="Permalink to &quot;API エンドポイント&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エンドポイント</th><th>説明</th></tr></thead><tbody><tr><td><code>GET/POST/PATCH/DELETE /api/store/time-limit-plans.php</code></td><td>プラン CRUD</td></tr><tr><td><code>GET/POST/PATCH/DELETE /api/store/plan-menu-items.php</code></td><td>プラン専用品目 CRUD</td></tr><tr><td><code>GET/POST /api/store/time-limit-plans-csv.php</code></td><td>プラン CSV</td></tr><tr><td><code>GET/POST /api/store/plan-menu-items-csv.php</code></td><td>プラン品目 CSV</td></tr><tr><td><code>GET/POST/PATCH/DELETE /api/store/course-templates.php</code></td><td>コース CRUD</td></tr><tr><td><code>POST/PATCH/DELETE /api/store/course-phases.php</code></td><td>フェーズ管理</td></tr><tr><td><code>GET/POST /api/store/course-csv.php</code></td><td>コース CSV</td></tr><tr><td><code>POST /api/kds/advance-phase.php</code></td><td>KDS 側でフェーズ進行</td></tr></tbody></table><h3 id="フロントエンド" tabindex="-1">フロントエンド <a class="header-anchor" href="#フロントエンド" aria-label="Permalink to &quot;フロントエンド&quot;">​</a></h3><ul><li><code>public/admin/js/time-limit-plan-editor.js</code> — プラン編集 UI（IIFE モジュール）</li><li><code>public/admin/js/course-editor.js</code> — コース編集 UI（IIFE モジュール、フェーズ含む）</li><li><code>public/kds/js/kds-app.js</code> — KDS のコースフェーズ表示・自動進行ロジック</li><li><code>public/handy/js/handy-app.js</code> — 着席モーダル（プラン・コース選択）</li><li><code>public/customer/js/menu-app.js</code> — セルフメニュー側のプラン適用 / フェーズ表示</li></ul><h3 id="認証・権限" tabindex="-1">認証・権限 <a class="header-anchor" href="#認証・権限" aria-label="Permalink to &quot;認証・権限&quot;">​</a></h3><ul><li>全 API は <code>require_role(&#39;manager&#39;)</code> 以上</li><li>店舗境界は <code>require_store_access($storeId)</code> で検証</li><li>マルチテナント境界はクエリの <code>store_id</code> 絞り込みで担保</li></ul><h3 id="設計上の注意" tabindex="-1">設計上の注意 <a class="header-anchor" href="#設計上の注意" aria-label="Permalink to &quot;設計上の注意&quot;">​</a></h3><ul><li>プランとコースは <strong>テーブルセッションレベルで排他</strong>（DB 制約はないがアプリ層で制御）</li><li><code>course_phases.items</code> は JSON 文字列（<code>[{name,qty}]</code>）</li><li>フェーズ番号 (<code>phase_number</code>) はコース内連番、再採番ロジックは現状なし（削除→再追加で詰め直し推奨）</li><li><code>auto_fire_min</code> が NULL = 手動進行、整数 = 自動進行（最小 0 分、推奨 5〜30 分）</li></ul></div><hr><h2 id="関連章" tabindex="-1">関連章 <a class="header-anchor" href="#関連章" aria-label="Permalink to &quot;関連章&quot;">​</a></h2><ul><li><a href="./04-menu.html">4. メニュー</a> — カテゴリ・通常メニュー管理</li><li><a href="./06-orders.html">6. 注文</a> — KDS 側の注文・フェーズ表示</li><li><a href="./07-kds.html">7. KDS</a> — KDS でのフェーズ進行操作</li><li><a href="./24-reservations.html">24. 予約管理</a> — コース予約との連携</li></ul><hr><h2 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h2><ul><li><strong>2026-04-19</strong>: フル粒度化（Phase B Batch-11）。操作前チェックリスト・入力例・ASCII 画面図・FAQ 28 件・トラブル表 12 件・運用ケース 3 件 追加。プラン専用メニュー（plan_menu_items）の手順を実装に合わせて再構成</li><li><strong>2026-04-18</strong>: フル粒度化、FAQ + トラブル + 技術補足 追加</li></ul>`,205)])])}const u=a(e,[["render",l]]);export{b as __pageData,u as default};
